// Feishu API configuration
const feishuConfig = {
  appId: "cli_a944a4e852385cc9",
  appSecret: "iiJSwleMNwXeSMf4ayN72bKLNFEZnqrP",
  endpoint: "https://open.feishu.cn"
};

// Get tenant access token
async function getTenantAccessToken() {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/auth/v3/tenant_access_token/internal`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      app_id: feishuConfig.appId,
      app_secret: feishuConfig.appSecret
    })
  });
  const data = await response.json();
  if (data.code !== 0) {
    throw new Error(`Failed to get token: ${data.msg}`);
  }
  return data.tenant_access_token;
}

// Create spreadsheet
async function createSpreadsheet(token) {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v3/spreadsheets`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      title: `Amazon产品分析 - ${productData.keyword}`,
      sheets: [
        {
          title: "产品特性分析",
          column_count: 5,
          row_count: 25
        },
        {
          title: "热销产品榜单",
          column_count: 6,
          row_count: 10
        },
        {
          title: "市场数据汇总",
          column_count: 4,
          row_count: 15
        }
      ]
    })
  });
  const data = await response.json();
  if (data.code !== 0) {
    throw new Error(`Failed to create spreadsheet: ${data.msg}`);
  }
  return data.data.spreadsheet.spreadsheet_token;
}

// Write data to spreadsheet
async function writeSpreadsheetData(token, spreadsheetToken) {
  const sheetId = spreadsheetToken;

  // Write feature analysis data
  const featureRows = [
    ["产品特性", "产品数量占比", "月销量占比", "说明"]
  ];
  productData.features.forEach(f => {
    featureRows.push([f.feature, f.productRatio, f.salesRatio, f.description]);
  });

  // Write hot products data
  const productRows = [
    ["排名", "品牌", "价格", "月销量", "特点"]
  ];
  productData.hotProducts.forEach(p => {
    productRows.push([p.rank, p.brand, p.price, p.monthlySales, p.feature]);
  });

  // Write summary data
  const summaryRows = [
    ["关键词", productData.keyword],
    ["市场", productData.market],
    ["数据来源", "Sorftime"],
    ["更新时间", new Date().toLocaleString('zh-CN')],
    [""],
    ["统计指标", "数值"],
    ["分析产品数", "46"],
    ["特性数量", productData.features.length],
    ["热销产品数", productData.hotProducts.length]
  ];

  console.log('准备写入飞书多维表格...');
  console.log('Spreadsheet Token:', spreadsheetToken);
  console.log('\n产品特性数据:');
  console.log(featureRows.slice(0, 5).map(r => r.join(' | ')).join('\n'));
  console.log('\n热销产品数据:');
  console.log(productRows.map(r => r.join(' | ')).join('\n'));
  console.log('\n汇总数据:');
  console.log(summaryRows.map(r => r.join(' | ')).join('\n'));

  return { featureRows, productRows, summaryRows };
}

// Main function
async function main() {
  try {
    console.log('🚀 开始创建飞书多维表格...\n');

    // Get access token
    console.log('📝 获取访问令牌...');
    const token = await getTenantAccessToken();
    console.log('✅ 访问令牌获取成功\n');

    // Create spreadsheet
    console.log('📊 创建多维表格...');
    const spreadsheetToken = await createSpreadsheet(token);
    console.log('✅ 多维表格创建成功');
    console.log('🔗 Spreadsheet Token:', spreadsheetToken, '\n');

    // Write data
    console.log('📝 写入数据...');
    const data = await writeSpreadsheetData(token, spreadsheetToken);
    console.log('✅ 数据准备完成\n');

    // Print spreadsheet URL
    const spreadsheetUrl = `https://docs.feishu.cn/sheets/${spreadsheetToken}`;
    console.log('✅ 飞书多维表格创建完成！');
    console.log('🔗 访问链接:', spreadsheetUrl);
    console.log('\n📋 数据摘要:');
    console.log(`   - 产品特性: ${productData.features.length} 条`);
    console.log(`   - 热销产品: ${productData.hotProducts.length} 条`);
    console.log(`   - 汇总数据: ${data.summaryRows.length} 条`);

  } catch (error) {
    console.error('❌ 错误:', error.message);
  }
}

main();

