  if (data.code !== 0) {
    throw new Error(`Failed to get token: ${data.msg}`);
  }
  return data.tenant_access_token;
}

// Create spreadsheet
async function createSpreadsheet(token) {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v3/spreadsheets`, {
