  ];
  productData.features.forEach(f => {
    featureRows.push([f.feature, f.productRatio, f.salesRatio, f.description]);
  });

  // Write hot products data
  const productRows = [
    ["排名", "品牌", "价格", "月销量", "特点"]
  ];
  productData.hotProducts.forEach(p => {
    productRows.push([p.rank, p.brand, p.price, p.monthlySales, p.feature]);
  });

  // Write summary data
  const summaryRows = [
    ["关键词", productData.keyword],
    ["市场", productData.market],
    ["数据来源", "Sorftime"],
    ["更新时间", new Date().toLocaleString('zh-CN')],
    [""],
    ["统计指标", "数值"],
    ["分析产品数", "46"],
    ["特性数量", productData.features.length],
    ["热销产品数", productData.hotProducts.length]
  ];

