  console.log(productRows.map(r => r.join(' | ')).join('\n'));
  console.log('\n汇总数据:');
  console.log(summaryRows.map(r => r.join(' | ')).join('\n'));

  return { featureRows, productRows, summaryRows };
}

// Main function
async function main() {
  try {
    console.log('🚀 开始创建飞书多维表格...\n');

    // Get access token
    console.log('📝 获取访问令牌...');
    const token = await getTenantAccessToken();
    console.log('✅ 访问令牌获取成功\n');

    // Create spreadsheet
    console.log('📊 创建多维表格...');
    const spreadsheetToken = await createSpreadsheet(token);
    console.log('✅ 多维表格创建成功');
    console.log('🔗 Spreadsheet Token:', spreadsheetToken, '\n');

    // Write data
    console.log('📝 写入数据...');
    const data = await writeSpreadsheetData(token, spreadsheetToken);
    console.log('✅ 数据准备完成\n');

    // Print spreadsheet URL
    const spreadsheetUrl = `https://docs.feishu.cn/sheets/${spreadsheetToken}`;
    console.log('✅ 飞书多维表格创建完成！');
    console.log('🔗 访问链接:', spreadsheetUrl);
    console.log('\n📋 数据摘要:');
    console.log(`   - 产品特性: ${productData.features.length} 条`);
    console.log(`   - 热销产品: ${productData.hotProducts.length} 条`);
    console.log(`   - 汇总数据: ${data.summaryRows.length} 条`);

  } catch (error) {
    console.error('❌ 错误:', error.message);
  }
}

main();

