    const featureUpdates = [];
    productData.features.forEach((f, index) => {
      const row = index + 2;
      featureUpdates.push({
        range: `产品特性分析!A${row}`,
        values: [[f.feature]]
      });
      featureUpdates.push({
        range: `产品特性分析!B${row}`,
        values: [[f.productRatio]]
      });
      featureUpdates.push({
        range: `产品特性分析!C${row}`,
        values: [[f.salesRatio]]
      });
      featureUpdates.push({
        range: `产品特性分析!D${row}`,
        values: [[f.description]]
      });
    });

    // Add header
    featureUpdates.unshift(
      { range: "产品特性分析!A1", values: [["产品特性"]] },
      { range: "产品特性分析!B1", values: [["产品数量占比"]] },
      { range: "产品特性分析!C1", values: [["月销量占比"]] },
      { range: "产品特性分析!D1", values: [["说明"]] }
    );

