async function getTenantAccessToken() {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/auth/v3/tenant_access_token/internal`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      app_id: feishuConfig.appId,
      app_secret: feishuConfig.appSecret
    })
  });
  const data = await response.json();
  return data.tenant_access_token;
}

async function writeRange(token, range, values) {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v2/spreadsheets/${feishuConfig.spreadsheetToken}/values`, {
    method: 'PUT',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      valueRange: {
        range: range,
        values: values
      }
    })
  });

  const text = await response.text();
  try {
    return JSON.parse(text);
  } catch {
    return { code: -1, msg: 'Invalid JSON response', raw: text };
  }
}

async function writeBatchData(token) {
  const results = [];

  // Write feature data (Sheet 0)
