  ]]));

  // Data rows
  for (const f of productData.features) {
    results.push(await writeRange(token, "产品特性分析!A2:D2", [[
      f.feature, f.productRatio, f.salesRatio, f.description
    ]]));
  }

  // Write hot products data (Sheet 1)
  console.log('🔥 写入热销产品数据...');

  // Header
  results.push(await writeRange(token, "热销产品榜单!A1", [[
    "排名", "品牌", "价格", "月销量", "特点"
  ]]));

  // Data rows
  for (const p of productData.hotProducts) {
    results.push(await writeRange(token, "热销产品榜单!A2:E2", [[
      p.rank, p.brand, p.price, p.monthlySales, p.feature
    ]]));
  }

  // Write summary data
  console.log('📈 写入汇总数据...');
