    ["价格区间", "$27.99 - $79.99"],
    ["总月销量", "49199"],
    ["平均价格", "$52.70"],
    ["最高销量", "16883"]
  ];

  for (const row of summaryData) {
    results.push(await writeRange(token, "市场数据汇总!A1:B1", [row]));
  }

  return results;
}

