  console.log(`   └─ 数据来源: Sorftime (Amazon US)`);

  console.log('\n💰 价格分析:');
  const prices = productData.hotProducts.map(p => p.price);
  const avgPrice = (prices.reduce((a, b) => a + b, 0) / prices.length).toFixed(2);
