  console.log('   └─ 总月销量: 49,199');

  console.log('\n🏆 热销品牌 Top 3 (按月销量):');
  const sorted = [...productData.hotProducts].sort((a, b) => b.monthlySales - a.monthlySales);
  sorted.slice(0, 3).forEach((p, i) => {
    console.log(`   ${i + 1}. ${p.brand.padEnd(15)} - $${p.price.toFixed(2)} (${p.monthlySales.toLocaleString()} 月销量)`);
  });

  console.log('\n🌟 关键产品特性 (按产品数量占比):');
  const sortedFeatures = [...productData.features].sort((a, b) =>
    parseFloat(b.productRatio) - parseFloat(a.productRatio)
  );
  sortedFeatures.slice(0, 5).forEach((f, i) => {
    console.log(`   ${i + 1}. ${f.feature.padEnd(20)} - ${f.productRatio} (产品占比)`);
  });

  console.log('\n🔗 访问飞书多维表格:');
  console.log(`   https://docs.feishu.cn/sheets/${feishuConfig.spreadsheetToken}`);

  console.log('\n💡 后续操作建议:');
  console.log('   1. 打开飞书表格，查看已创建的3个工作表');
  console.log('   2. 使用飞书表格的"图表"功能创建可视化仪表盘');
  console.log('   3. 可创建饼图展示产品特性占比');
  console.log('   4. 可创建柱状图展示热销产品对比');
  console.log('   5. 支持多人协作实时编辑');
  console.log('   6. 可设置定时刷新数据');

  console.log('\n📈 推荐仪表盘布局:');
  console.log('   ┌─────────────────────────────────────┐');
  console.log('   │  A4便携式热敏打印机市场分析仪表盘   │');
  console.log('   ├──────────────┬──────────────────────┤');
  console.log('   │ 饼图:        │ 柱状图:              │');
  console.log('   │ 产品特性占比 │ 热销产品月销量       │');
  console.log('   ├──────────────┴──────────────────────┤');
  console.log('   │ 数据卡片:                            │');
  console.log('   │ [总销量] [平均价格] [产品数]         │');
  console.log('   └─────────────────────────────────────┘');

  console.log('\n📋 完整数据列表:');
  console.log('\n   --- 产品特性分析 (前5) ---');
  productData.features.slice(0, 5).forEach((f, i) => {
    console.log(`   ${i + 1}. ${f.feature}`);
    console.log(`      产品占比: ${f.productRatio} | 销量占比: ${f.salesRatio}`);
  });

  console.log('\n   --- 热销产品榜单 ---');
  productData.hotProducts.forEach((p, i) => {
    console.log(`   ${i + 1}. ${p.brand} - $${p.price} - ${p.monthlySales.toLocaleString()} 月销量`);
  });
}

async function main() {
  try {
    console.log('🚀 开始写入飞书多维表格数据...\n');
    const token = await getTenantAccessToken();
    console.log('✅ 访问令牌获取成功\n');

    const results = await writeBatchData(token);

    const successCount = results.filter(r => r.code === 0 || !r.code).length;
    console.log(`\n✅ 数据写入完成 (成功: ${successCount}/${results.length})`);

    // Check for errors
    const errors = results.filter(r => r.code && r.code !== 0);
    if (errors.length > 0) {
      console.log('\n⚠️  部分数据写入可能需要手动操作:');
      errors.forEach(e => {
        if (e.msg) console.log(`   - ${e.msg}`);
      });
    }

    displayResults();

  } catch (error) {
    console.error('❌ 错误:', error.message);
  }
}

main();

