async function getTenantAccessToken() {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/auth/v3/tenant_access_token/internal`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      app_id: feishuConfig.appId,
      app_secret: feishuConfig.appSecret
    })
  });
  const data = await response.json();
  return data.tenant_access_token;
}

async function getSpreadsheetSheets(token) {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v3/spreadsheets/${feishuConfig.spreadsheetToken}/sheets/query`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    }
  });
  return await response.json();
}

async function appendRow(token, sheetId, values) {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v2/spreadsheets/${feishuConfig.spreadsheetToken}/sheets/${sheetId}/rows`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      rows: [{
        values: values.map(v => ({ v: v }))
      }]
    })
  });
  return await response.json();
}

async function updateCells(token, sheetId, startRow, startColumn, values) {
  // Calculate end column based on data
  const maxCols = Math.max(...values.map(row => row.length));
  const endColumn = startColumn + maxCols - 1;
  const endRow = startRow + values.length - 1;

  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v2/spreadsheets/${feishuConfig.spreadsheetToken}/sheets/${sheetId}/cells/${startRow}_${startColumn}/${endRow}_${endColumn}`, {
    method: 'PUT',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      value: {
        values: values.map(row => row.map(v => ({ v: v })))
      }
    })
  });
  return await response.json();
}

async function writeDataToSheets(token) {
