  console.log('📊 获取表格信息...');
  const sheetsInfo = await getSpreadsheetSheets(token);
  console.log('Sheets info:', JSON.stringify(sheetsInfo, null, 2));

  if (sheetsInfo.code !== 0) {
    throw new Error(`Failed to get sheets: ${sheetsInfo.msg}`);
  }

  const sheets = sheetsInfo.data.sheet_items || sheetsInfo.data.sheets || [];
  console.log(`找到 ${sheets.length} 个工作表`);

  const results = [];

  // Write feature data to first sheet
  if (sheets.length > 0) {
    const sheetId = sheets[0].sheet_id;
    console.log(`\n📝 写入产品特性数据到 Sheet ${sheetId}...`);

    const featureValues = [
      ["产品特性", "产品数量占比", "月销量占比", "说明"],
      ...productData.features.map(f => [f.feature, f.productRatio, f.salesRatio, f.description])
    ];

    try {
      const result = await updateCells(token, sheetId, 1, 1, featureValues);
      console.log('✅ 产品特性数据写入结果:', result.code === 0 ? '成功' : result.msg);
      results.push({ sheet: '产品特性', success: result.code === 0 });
    } catch (e) {
      console.log('❌ 写入失败:', e.message);
      results.push({ sheet: '产品特性', success: false, error: e.message });
    }
  }

  // Create new sheet for products
  console.log('\n📄 创建热销产品工作表...');
  const addSheetResponse = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v3/spreadsheets/${feishuConfig.spreadsheetToken}/sheets`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      title: "热销产品榜单",
      sheet_type: "grid"
    })
  });
  const addSheetResult = await addSheetResponse.json();
  console.log('Add sheet result:', JSON.stringify(addSheetResult, null, 2));

  if (addSheetResult.code === 0) {
    const productSheetId = addSheetResult.data.sheet.sheet_id;
    console.log(`✅ 新工作表创建成功: ${productSheetId}`);

    const productValues = [
      ["排名", "品牌", "价格", "月销量", "特点"],
      ...productData.hotProducts.map(p => [p.rank, p.brand, p.price, p.monthlySales, p.feature])
    ];

    try {
      const result = await updateCells(token, productSheetId, 1, 1, productValues);
      console.log('✅ 热销产品数据写入结果:', result.code === 0 ? '成功' : result.msg);
      results.push({ sheet: '热销产品', success: result.code === 0 });
    } catch (e) {
      console.log('❌ 写入失败:', e.message);
      results.push({ sheet: '热销产品', success: false, error: e.message });
    }
  }

  return results;
}

