  console.log('排名\t品牌\t价格\t月销量\t特点');
  productData.hotProducts.forEach(p => {
    console.log(`${p.rank}\t${p.brand}\t${p.price}\t${p.monthlySales}\t${p.feature}`);
  });

  console.log('\n\n【市场数据汇总】:\n');
  console.log('关键词\tA4 Portable Thermal Printer');
  console.log('市场\tAmazon US');
  console.log('数据来源\tSorftime');
  console.log('更新时间\t' + new Date().toLocaleString('zh-CN'));
  console.log('\n统计指标\t数值');
  console.log('分析产品数\t46');
  console.log('特性数量\t' + productData.features.length);
  console.log('热销产品数\t' + productData.hotProducts.length);
  console.log('价格区间\t$27.99 - $79.99');
  console.log('总月销量\t49199');
  console.log('平均价格\t$52.70');
