async function getTenantAccessToken() {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/auth/v3/tenant_access_token/internal`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      app_id: feishuConfig.appId,
      app_secret: feishuConfig.appSecret
    })
  });
  const data = await response.json();
  return data.tenant_access_token;
}

async function createNewSpreadsheet(token) {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v3/spreadsheets`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      title: `Temu热敏打印机分析-${new Date().toISOString().slice(0,10)}`
    })
  });
  return await response.json();
}

async function appendDataToSheet(token, spreadsheetToken, sheetId, rows) {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/sheets/${sheetId}/rows`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      rows: rows.map(row => ({
        values: row.map(v => ({ v: v }))
      }))
    })
  });
  return await response.text();
}

