    console.log('📊 创建新的多维表格...');
    const createResult = await createNewSpreadsheet(token);
    console.log('Create result:', JSON.stringify(createResult, null, 2));

    if (createResult.code !== 0) {
      throw new Error(`Failed to create: ${createResult.msg}`);
    }

    const spreadsheetToken = createResult.data.spreadsheet.spreadsheet_token;
    const url = createResult.data.spreadsheet.url;

    console.log('\n✅ 表格创建成功!');
    console.log('🔗 Token:', spreadsheetToken);
    console.log('🔗 URL:', url);

    // Try to get the first sheet ID
    let sheetId = "0";
    try {
      const infoResponse = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v3/spreadsheets/${spreadsheetToken}`, {
        method: 'GET',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const info = await infoResponse.json();
      if (info.code === 0 && info.data.spreadsheet.sheets) {
        sheetId = info.data.spreadsheet.sheets[0].sheet_id;
        console.log('📄 Sheet ID:', sheetId);
      }
    } catch (e) {
      console.log('Using default sheet ID: 0');
    }

    // Combine all data
    const allRows = [
      ...temuData.products,
      [""],
      ...temuData.comparison,
      [""],
      ...temuData.insights
    ];

    console.log('\n📝 写入数据...');
    console.log(`   准备写入 ${allRows.length} 行数据...\n`);

    const appendResult = await appendDataToSheet(token, spreadsheetToken, sheetId, allRows);
    console.log('Append result:', appendResult);

    console.log('\n' + '='.repeat(80));
    console.log('✅ 飞书多维表格创建完成！');
    console.log('='.repeat(80));

    console.log('\n🔗 访问链接:');
    console.log(`   ${url}`);

    console.log('\n💡 请刷新页面查看数据！');
    console.log('   如数据未显示，请手动复制以下数据:\n');

    console.log('排名\t型号\t价格\t评分\t评价数\t特点');
    temuData.products.slice(1).forEach(row => {
      console.log(row.join('\t'));
    });

  } catch (error) {
    console.error('❌ 错误:', error.message);
  }
}

main();

