  return data.tenant_access_token;
}

async function getSpreadsheetInfo(token) {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v3/spreadsheets/${feishuConfig.spreadsheetToken}`, {
    method: 'GET',
    headers: { 'Authorization': `Bearer ${token}` }
