  console.log('Spreadsheet info:', text);
  try {
    return JSON.parse(text);
  } catch {
    return { code: -1, msg: 'Invalid JSON', raw: text };
  }
}

async function appendRows(token, sheetId, rows) {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v2/spreadsheets/${feishuConfig.spreadsheetToken}/sheets/${sheetId}/rows`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      rows: rows.map(row => ({
        values: row.map(v => ({ v: v }))
      }))
    })
  });
  const text = await response.text();
  console.log('Append rows response:', text);
  try {
    return JSON.parse(text);
  } catch {
    return { code: -1, msg: 'Invalid JSON', raw: text };
  }
}

async function addSheetAndWrite(token) {
  // Add second sheet
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v3/spreadsheets/${feishuConfig.spreadsheetToken}/sheets`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      title: "产品特性分析",
      sheet_type: "grid"
    })
  });
  const data = await response.json();
  console.log('Add sheet response:', JSON.stringify(data, null, 2));

  if (data.code === 0) {
    const featureSheetId = data.data.sheet.sheet_id;
    console.log('Feature sheet created:', featureSheetId);

    // Write feature data
    const featureRows = [
      ...temuData.features,
      [""],
      ["📈 Temu 市场特点", "", ""],
      ["• 价格优势", "比亚马逊低 54%", ""],
      ["• 品牌分布", "白牌/贴牌为主", ""],
      ["• 热销型号", "M832 Pro 系列", ""]
    ];

    const result = await appendRows(token, featureSheetId, featureRows);
    return { sheetId: featureSheetId, success: result.code === 0 };
  }

  return { sheetId: null, success: false };
}

