      ["• 热销型号", "M832 Pro 2025", "", "", "", ""],
      ["• 目标客户", "预算敏感用户", "", "", "", ""],
      [""],
      ["💡 购买建议", "", "", "", "", ""],
      ["预算有限", "选 Temu (M832 Pro $25.99)", "", "", "", ""],
      ["品质优先", "选亚马逊 (Amazon Basics $28.78)", "", "", "", ""]
    ];

    console.log('📝 写入产品数据...');
