    console.log('='.repeat(80));

    console.log('\n🔗 访问链接:');
    console.log('   https://ecnn53rxijcm.feishu.cn/sheets/YOnrspCSthPDqAtSqPmcQu3fnyp');

    console.log('\n📊 数据统计:');
    console.log(`   • 产品数据: ${result1.code === 0 ? '✅ 成功' : '❌ 失败'}`);
