  ["• 目标客户", "预算敏感", "", "", "", ""]
];

async function getTenantAccessToken() {
  const response = await fetch(`${feishuConfig.endpoint}/open-apis/auth/v3/tenant_access_token/internal`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      app_id: feishuConfig.appId,
      app_secret: feishuConfig.appSecret
    })
  });
  const data = await response.json();
  return data.tenant_access_token;
}

async function createAndWrite() {
  const token = await getTenantAccessToken();

  const createResponse = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v3/spreadsheets`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      title: `Temu热敏打印机-${Date.now()}`
    })
  });
  const createData = await createResponse.json();

  if (createData.code !== 0) {
    throw new Error(createData.msg);
  }

  const spreadsheetToken = createData.data.spreadsheet.spreadsheet_token;
  const url = createData.data.spreadsheet.url;
  const sheetId = createData.data.spreadsheet.sheets[0].sheet_id;

  console.log('✅ 表格创建成功!');
  console.log('URL:', url);
  console.log('Sheet ID:', sheetId);

  // Try to append rows
  console.log('\n📝 写入数据...');
  const appendResponse = await fetch(`${feishuConfig.endpoint}/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/sheets/${sheetId}/rows`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      rows: data.map(row => ({
        values: row.map(v => ({ v: v }))
      }))
    })
  });

  const appendText = await appendResponse.text();
  console.log('Append result:', appendText);

  return { url, spreadsheetToken };
}

function displayCopyData(url) {
  console.log('\n' + '='.repeat(80));
  console.log('📋 复制以下数据到飞书表格');
  console.log('='.repeat(80));

  console.log('\n🔗 访问链接:', url);
  console.log('\n请复制以下数据:\n');

  console.log('排名\t型号\t价格\t评分\t评价数\t特点');
  data.forEach((row, i) => {
    if (i === 0 || (row[0] !== "" && typeof row[0] === 'number')) {
      console.log(row.join('\t'));
    }
  });
}

async function main() {
  try {
    console.log('🚀 写入数据到飞书表格...\n');
    const result = await createAndWrite();
    displayCopyData(result.url);
  } catch (error) {
    console.error('❌ 错误:', error.message);
  }
}

main();

